import React, { useCallback } from 'react';
import { ActionButton, LinkButton } from './duels-primitives';
import { HOME_ROUTE, LOBBY_CHAT_PREVIEW_LIMIT } from './utils/duels-ui';
import { createKangurDuelsHref } from './duelsHref';
import { useKangurDuelsScreenData } from './useKangurDuelsScreenData';
import { DuelsScreenContent } from './DuelsScreenContent';

export function KangurDuelsScreen(): React.JSX.Element {
  const data = useKangurDuelsScreenData();

  const createLoginCallToAction = useCallback((label: string) => (
    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
    data.supportsLearnerCredentials ? <LinkButton href={HOME_ROUTE} label={label} stretch tone='primary' /> : <ActionButton label={label} onPress={data.signIn} stretch />
  ), [data.signIn, data.supportsLearnerCredentials]);

  const renderJoinAction = useCallback((id: string) => {
    const label = data.copy({ de: 'Duell beitreten', en: 'Join duel', pl: 'Dołącz do pojedynku' });
    if (data.lobby.isAuthenticated) {

      return <ActionButton label={label} onPress={() => data.joinDuelAction(id)} stretch />;
    }
    return createLoginCallToAction(data.copy({ de: 'Anmelden, um beizutreten', en: 'Sign in to join', pl: 'Zaloguj, aby dołączyć' }));
  }, [data.copy, createLoginCallToAction, data.lobby.isAuthenticated, data.joinDuelAction]);


  const renderSpectateAction = useCallback((id: string) => (
    <LinkButton href={createKangurDuelsHref({ sessionId: id, spectate: true })} label={data.copy({ de: 'Duell beobachten', en: 'Watch duel', pl: 'Obserwuj pojedynek' })} stretch tone='secondary' />
  ), [data.copy]);

  const autoRefreshChipLabel = data.lobbyActions.autoRefreshEnabled
    ? data.copy({ de: 'Auto-Refresh (Ein)', en: 'Auto refresh (On)', pl: 'Auto odświeżanie (Włączone)' })
    : data.copy({ de: 'Auto-Refresh (Aus)', en: 'Auto refresh (Off)', pl: 'Auto odświeżanie (Wyłączone)' });

  const canSend = data.chat.isAuthenticated && !data.chat.isSending && data.lobbyActions.chatDraft.trim().length > 0 && data.lobbyActions.chatDraft.trim().length <= data.chat.maxMessageLength;

  return (
    <DuelsScreenContent
      {...data}
      autoRefreshChipLabel={autoRefreshChipLabel}
      autoRefreshEnabled={data.lobbyActions.autoRefreshEnabled}
      canSendChatMessage={canSend}
      chatActionError={data.lobbyActions.chatActionError}
      chatDraft={data.lobbyActions.chatDraft}
      chatRemainingChars={Math.max(0, data.chat.maxMessageLength - data.lobbyActions.chatDraft.length)}
      createLoginCallToAction={createLoginCallToAction}
      handleInviteShare={data.sessionActions.handleInviteShare}
      handleLobbyChatSend={data.lobbyActions.handleLobbyChatSend}
      handleRematch={data.sessionActions.handleRematch}
      isJoiningFromRoute={data.routeJoin.isJoiningFromRoute}
      joinSessionFromRoute={data.routeJoin.joinSessionFromRoute}
      lobbyChatPreview={data.chat.messages.slice(-LOBBY_CHAT_PREVIEW_LIMIT)}
      onChatDraftChange={(v) => { data.lobbyActions.setChatDraft(v); if (data.lobbyActions.chatActionError !== null) data.lobbyActions.setChatActionError(null); }}
      onToggleAutoRefresh={() => data.lobbyActions.setAutoRefreshEnabled((p) => !p)}
      renderJoinAction={renderJoinAction}
      renderSpectateAction={renderSpectateAction}
      routeJoinError={data.routeJoin.routeJoinError}
      sessionState={{ ...data.sessionState, inviteShareError: data.sessionActions.inviteShareError }}
    />
  );
}

import { useQuery, type UseQueryResult } from '@tanstack/react-query';
import type { KangurDuelLobbyEntry, KangurDuelLobbyResponse } from '@kangur/contracts/kangur-duels';
import { useEffect, useMemo } from 'react';
import type { KangurAuthSession } from '@kangur/platform';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { resolveMobileDuelErrorMessage } from '../duels/mobileDuelErrorMessages';
import {
  buildKangurMobileHomeDuelLobbyQueryKey,
  MOBILE_HOME_DUEL_LOBBY_POLL_MS,
  MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT,
} from './homeDuelLobbyQuery';
import {
  persistKangurMobileHomeDuelInvites,
  resolvePersistedKangurMobileHomeDuelInvites,
} from './persistedKangurMobileHomeDuelInvites';
import type { DuelApiClient } from '../duels/useKangurMobileDuelsLobbyQueries';

const MOBILE_HOME_DUELS_INVITES_DISPLAY_LIMIT = 4;

type UseKangurMobileHomeDuelsInvitesResult = {
  error: string | null;
  invites: KangurDuelLobbyEntry[];
  isDeferred: boolean;
  isAuthenticated: boolean;
  isLoading: boolean;
  outgoingChallenges: KangurDuelLobbyEntry[];
  isRestoringAuth: boolean;
  refresh: () => Promise<void>;
};

type UseKangurMobileHomeDuelsInvitesOptions = {
  enabled?: boolean;
};

function getLearnerId(user: any): string | null {
    return user.activeLearner?.id ?? null;
}
function getUserId(user: any): string | null {
    return user.id ?? null;
}
function getIdentity(user: any, learnerId: string | null, userId: string | null): string {
    return learnerId ?? user.email ?? userId ?? 'guest';
}
function resolveLearnerContext(
  session: KangurAuthSession,
): { identity: string; activeId: string | null } {
  const user = session.user;
  if (!user) return { identity: 'guest', activeId: null };
  const learnerId = getLearnerId(user);
  const userId = getUserId(user);
  return { identity: getIdentity(user, learnerId, userId), activeId: learnerId ?? userId };
}

function useDuelsState(
  isQueryEnabled: boolean,
  invitesQuery: UseQueryResult<KangurDuelLobbyResponse, Error>,
  persisted: KangurDuelLobbyEntry[] | null
) {
  const data = invitesQuery.data;
  const privateEntries = useMemo(() => data?.entries?.filter((e) => e.visibility === 'private').sort((l, r) => Date.parse(r.updatedAt) - Date.parse(l.updatedAt)).slice(0, MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT) ?? [], [data]);
  const hasResolvedLive = isQueryEnabled && !invitesQuery.isLoading && invitesQuery.error === null && data !== undefined;
  const resolved: KangurDuelLobbyEntry[] = useMemo(() => hasResolvedLive ? privateEntries : (persisted ?? privateEntries), [hasResolvedLive, privateEntries, persisted]);
  return { resolved, hasResolvedLive, privateEntries };
}

function useLearnerContext(): { identity: string; activeId: string | null } {
  const { session } = useKangurMobileAuth();
  return useMemo(() => resolveLearnerContext(session), [session]);
}

function filterEntries(entries: KangurDuelLobbyEntry[]): KangurDuelLobbyEntry[] {
  return [...entries]
    .filter((e) => e.visibility === 'private')
    .sort((l, r) => Date.parse(r.updatedAt) - Date.parse(l.updatedAt))
    .slice(0, MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT);
}

function usePrivateEntriesQuery(
  enabled: boolean,
  apiBaseUrl: string,
  apiClient: DuelApiClient,
  learnerIdentity: string,
): UseQueryResult<KangurDuelLobbyResponse, Error> {
  return useQuery<KangurDuelLobbyResponse, Error>({
    enabled,
    queryKey: buildKangurMobileHomeDuelLobbyQueryKey(apiBaseUrl, learnerIdentity, 'private'),
    queryFn: async (): Promise<KangurDuelLobbyResponse> =>
      await apiClient.listDuelLobby({ limit: MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT, visibility: 'private' }, { cache: 'no-store' }),
    refetchInterval: MOBILE_HOME_DUEL_LOBBY_POLL_MS,
    staleTime: 10_000,
  });
}

export const useKangurMobileHomeDuelsInvites = ({
  enabled = true,
}: UseKangurMobileHomeDuelsInvitesOptions = {}): UseKangurMobileHomeDuelsInvitesResult => {
  const { copy } = useKangurMobileI18n();
  const { apiBaseUrl, apiClient, storage } = useKangurMobileRuntime();
  const { isLoadingAuth, session } = useKangurMobileAuth();
  const { identity: learnerIdentity, activeId: activeLearnerId } = useLearnerContext();

  const isAuthenticated = session.status === 'authenticated';
  const isQueryEnabled = enabled && isAuthenticated;

  const persisted = useMemo(
    () => isAuthenticated ? resolvePersistedKangurMobileHomeDuelInvites({ learnerIdentity, storage }) : null,
    [isAuthenticated, learnerIdentity, storage],
  );

  const invitesQuery = usePrivateEntriesQuery(isQueryEnabled, apiBaseUrl, apiClient, learnerIdentity);
  const { resolved, hasResolvedLive, privateEntries } = useDuelsState(isQueryEnabled, invitesQuery, persisted);

  useEffect(() => {
    if (hasResolvedLive) persistKangurMobileHomeDuelInvites({ entries: privateEntries, learnerIdentity, storage });
  }, [hasResolvedLive, learnerIdentity, privateEntries, storage]);

  const { invites, outgoingChallenges } = useCategorizedDuels(resolved, activeLearnerId);

  const error = resolveMobileDuelErrorMessage({
      error: invitesQuery.error instanceof Error ? invitesQuery.error : null,
      copy,
      fallback: { de: 'Die Duelleinladungen konnten nicht geladen werden.', en: 'Could not load duel invites.', pl: 'Nie udało się pobrać zaproszeń do pojedynków.' },
      unauthorized: { de: 'Melde dich an, um private Duelleinladungen zu laden.', en: 'Sign in to load private duel invites.', pl: 'Zaloguj się, aby pobrać prywatne zaproszenia do pojedynków.' },
  });

  return {
    error,
    invites,
    isDeferred: isAuthenticated && !(isLoadingAuth && !isAuthenticated) && !isQueryEnabled,
    isAuthenticated,
    isLoading: (isLoadingAuth && !isAuthenticated) || (isQueryEnabled && invitesQuery.isLoading),
    outgoingChallenges,
    isRestoringAuth: isLoadingAuth && !isAuthenticated,
    refresh: async () => { if (isQueryEnabled) await invitesQuery.refetch(); },
  };
};

import { useQuery, type UseQueryResult } from '@tanstack/react-query';
import type { KangurDuelLobbyEntry, KangurDuelLobbyResponse, KangurDuelStatus } from '@kangur/contracts/kangur-duels';
import { useMemo } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import {
  buildKangurMobileHomeDuelLobbyQueryKey,
  MOBILE_HOME_DUEL_LOBBY_POLL_MS,
  MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT,
} from './homeDuelLobbyQuery';
import type { DuelApiClient } from '../duels/useKangurMobileDuelsLobbyQueries';

const MOBILE_HOME_DUELS_SPOTLIGHT_LIMIT = 4;

type UseKangurMobileHomeDuelsSpotlightResult = {
  entries: KangurDuelLobbyEntry[];
  error: string | null;
  isLoading: boolean;
  refresh: () => Promise<void>;
};

type UseKangurMobileHomeDuelsSpotlightOptions = {
  enabled?: boolean;
};

const DUEL_SPOTLIGHT_STATUS_PRIORITY: Record<KangurDuelStatus, number> = {
  aborted: 5,
  completed: 4,
  created: 3,
  in_progress: 0,
  ready: 1,
  waiting: 2,
};

function isSpotlightEntry(entry: KangurDuelLobbyEntry): boolean {
  return entry.visibility === 'public' &&
    (entry.status === 'waiting' || entry.status === 'ready' || entry.status === 'in_progress');
}

function sortEntries(l: KangurDuelLobbyEntry, r: KangurDuelLobbyEntry): number {
    const priorityDelta = DUEL_SPOTLIGHT_STATUS_PRIORITY[l.status] - DUEL_SPOTLIGHT_STATUS_PRIORITY[r.status];
    return priorityDelta !== 0 ? priorityDelta : Date.parse(r.updatedAt) - Date.parse(l.updatedAt);
}

function getSpotlightEntries(raw: KangurDuelLobbyEntry[]): KangurDuelLobbyEntry[] {
    return raw.filter(isSpotlightEntry).sort(sortEntries).slice(0, MOBILE_HOME_DUELS_SPOTLIGHT_LIMIT);
}

function useSpotlightEntries(
    data: KangurDuelLobbyEntry[] | undefined
): KangurDuelLobbyEntry[] {
    const raw = data ?? [];
    return useMemo(() => getSpotlightEntries(raw), [raw]);
}

async function refreshSpotlight(
  enabled: boolean,
  spotlightQuery: UseQueryResult<KangurDuelLobbyResponse, Error>
): Promise<void> {
  if (enabled) await spotlightQuery.refetch();
}

export const useKangurMobileHomeDuelsSpotlight = (options: UseKangurMobileHomeDuelsSpotlightOptions = {}): UseKangurMobileHomeDuelsSpotlightResult => {
  const enabled = options.enabled ?? true;
  const { apiBaseUrl, apiClient } = useKangurMobileRuntime();
  const { session } = useKangurMobileAuth();
  const learnerIdentity = session.user?.activeLearner?.id ?? session.user?.email ?? session.user?.id ?? 'guest';

  const spotlightQuery: UseQueryResult<KangurDuelLobbyResponse, Error> = useQuery<KangurDuelLobbyResponse, Error>({
    enabled,
    queryKey: buildKangurMobileHomeDuelLobbyQueryKey(apiBaseUrl, learnerIdentity, 'public'),
    queryFn: async (): Promise<KangurDuelLobbyResponse> =>
      await (apiClient as DuelApiClient).listDuelLobby({ limit: MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT, visibility: 'public' }, { cache: 'no-store' }),
    refetchInterval: MOBILE_HOME_DUEL_LOBBY_POLL_MS,
    staleTime: 30_000,
  });

  const entries = useSpotlightEntries(spotlightQuery.data?.entries);
  const error = spotlightQuery.error instanceof Error ? spotlightQuery.error.message : null;
  const isLoading = enabled && spotlightQuery.isLoading;
  const refresh = async (): Promise<void> => { if (enabled) await spotlightQuery.refetch(); };

  return { entries, error, isLoading, refresh };
};

import { Text, View } from 'react-native';

import {
  getKangurMobileLocaleTag,
  useKangurMobileI18n,
} from '../i18n/kangurMobileI18n';
import { translateKangurMobileActionLabel } from '../shared/translateKangurMobileActionLabel';
import type { KangurMobileLessonCheckpointItem } from './useKangurMobileLessonCheckpoints';
import type { KangurMobileLessonsAssignmentItem } from './useKangurMobileLessonsAssignments';
import type { KangurMobileLessonsBadgeItem } from './useKangurMobileLessonsBadges';
import type { KangurMobileLessonsLessonMasteryItem } from './useKangurMobileLessonsLessonMastery';
import type { KangurMobileLessonsRecentResultItem } from './useKangurMobileLessonsRecentResults';
import {
  formatKangurMobileScoreDateTime,
  formatKangurMobileScoreOperation,
  getKangurMobileScoreAccuracyPercent,
} from '../scores/mobileScoreSummary';
import {
  KangurMobileInsetPanel as InsetPanel,
  KangurMobileLinkButton as LinkButton,
  KangurMobileMutedActionChip as MutedActionChip,
  KangurMobilePill as Pill,
  type KangurMobileTone as Tone,
} from '../shared/KangurMobileUi';
import { renderLessonPracticeLink } from './lessons-screen-primitives';

function LessonCheckpointHeader({
  item,
}: {
  item: KangurMobileLessonCheckpointItem;
}): React.JSX.Element {
  const { copy } = useKangurMobileI18n();
  return (
    <View
      style={{
        flexDirection: 'row',
        justifyContent: 'space-between',
        alignItems: 'flex-start',
        gap: 12,
      }}
    >
      <View style={{ flex: 1, gap: 4 }}>
        <Text style={{ color: '#0f172a', fontSize: 15, fontWeight: '800' }}>
          {item.emoji} {item.title}
        </Text>
        <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
          {copy({
            de: `Letztes Ergebnis ${item.lastScorePercent}% • Beherrschung ${item.masteryPercent}%`,
            en: `Last score ${item.lastScorePercent}% • mastery ${item.masteryPercent}%`,
            pl: `Ostatni wynik ${item.lastScorePercent}% • opanowanie ${item.masteryPercent}%`,
          })}
        </Text>
      </View>
      <Pill
        label={`${item.bestScorePercent}%`}
        tone={{
          backgroundColor: '#eef2ff',
          borderColor: '#c7d2fe',
          textColor: '#4338ca',
        }}
      />
    </View>
  );
}

export function LessonCheckpointRow({
  item,
}: {
  item: KangurMobileLessonCheckpointItem;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();

  return (
    <InsetPanel gap={10}>
      <LessonCheckpointHeader item={item} />

      <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
        {copy({
          de: 'Zuletzt gespeichert',
          en: 'Last saved',
          pl: 'Ostatni zapis',
        })}{' '}
        {new Intl.DateTimeFormat(getKangurMobileLocaleTag(locale), {
          dateStyle: 'medium',
          timeStyle: 'short',
        }).format(new Date(item.lastCompletedAt))}
      </Text>

      <View style={{ flexDirection: 'column', gap: 8 }}>
        <LinkButton
          href={item.lessonHref}
          label={`${copy({
            de: 'Zur Lektion zurück',
            en: 'Return to lesson',
            pl: 'Wróć do lekcji',
          })}: ${item.title}`}
          stretch
          tone='primary'
        />
        {renderLessonPracticeLink({
          href: item.practiceHref,
          label: `${copy({
            de: 'Danach trainieren',
            en: 'Practice after',
            pl: 'Potem trenuj',
          })}: ${item.title}`,
          fullWidth: true,
        })}
      </View>
    </InsetPanel>
  );
}

const resolvePriorityTone = (priority: string): Tone => {
  if (priority === 'high') {
    return {
      backgroundColor: '#fef2f2',
      borderColor: '#fecaca',
      textColor: '#b91c1c',
    };
  }

  if (priority === 'medium') {
    return {
      backgroundColor: '#fffbeb',
      borderColor: '#fde68a',
      textColor: '#b45309',
    };
  }

  return {
    backgroundColor: '#eff6ff',
    borderColor: '#bfdbfe',
    textColor: '#1d4ed8',
  };
};

const resolvePriorityLabel = (priority: string, copy: (m: Record<string, string>) => string): string => {
  if (priority === 'high') {
    return copy({ de: 'Hohe Priorität', en: 'High priority', pl: 'Priorytet wysoki' });
  }

  if (priority === 'medium') {
    return copy({ de: 'Mittlere Priorität', en: 'Medium priority', pl: 'Priorytet średni' });
  }

  return copy({ de: 'Niedrige Priorität', en: 'Low priority', pl: 'Priorytet niski' });
};

export function LessonsAssignmentRow({
  item,
}: {
  item: KangurMobileLessonsAssignmentItem;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const assignment = item.assignment as { priority: string; title: string; description: string; target: string; action: { label: string } };
  const priorityTone = resolvePriorityTone(assignment.priority);
  const priorityLabel = resolvePriorityLabel(assignment.priority, copy);
  const actionLabel = translateKangurMobileActionLabel(assignment.action.label, locale);
  const soonLabel = copy({ de: 'bald', en: 'soon', pl: 'wkrotce' });

  const assignmentAction =
    item.href !== null ? (
      <LinkButton href={item.href} label={actionLabel} stretch tone='primary' />
    ) : (
      <MutedActionChip label={`${actionLabel} · ${soonLabel}`} />
    );

  return (
    <InsetPanel gap={8}>
      <Pill label={priorityLabel} tone={priorityTone} />
      <Text style={{ color: '#0f172a', fontSize: 15, fontWeight: '800' }}>
        {assignment.title}
      </Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {assignment.description}
      </Text>
      <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
        {copy({
          de: `Ziel: ${assignment.target}`,
          en: `Goal: ${assignment.target}`,
          pl: `Cel: ${assignment.target}`,
        })}
      </Text>
      {assignmentAction}
    </InsetPanel>
  );
}

const getLessonMasteryTone = (masteryPercent: number): Tone => {
  if (masteryPercent >= 90) {
    return {
      backgroundColor: '#ecfdf5',
      borderColor: '#a7f3d0',
      textColor: '#047857',
    };
  }

  if (masteryPercent >= 70) {
    return {
      backgroundColor: '#fffbeb',
      borderColor: '#fde68a',
      textColor: '#b45309',
    };
  }

  return {
    backgroundColor: '#fef2f2',
    borderColor: '#fecaca',
    textColor: '#b91c1c',
  };
};

function LessonMasteryHeader({
  insight,
  title,
  masteryTone,
}: {
  insight: KangurMobileLessonsLessonMasteryItem;
  title: string;
  masteryTone: Tone;
}): React.JSX.Element {
  const { copy } = useKangurMobileI18n();
  return (
    <View
      style={{
        flexDirection: 'row',
        justifyContent: 'space-between',
        alignItems: 'flex-start',
        gap: 12,
      }}
    >
      <View style={{ flex: 1, gap: 4 }}>
        <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>{title}</Text>
        <Text style={{ color: '#0f172a', fontSize: 15, fontWeight: '800' }}>
          {insight.emoji} {insight.title}
        </Text>
        <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
          {copy({
            de: `Versuche ${insight.attempts} • letztes Ergebnis ${insight.lastScorePercent}%`,
            en: `Attempts ${insight.attempts} • last score ${insight.lastScorePercent}%`,
            pl: `Próby ${insight.attempts} • ostatni wynik ${insight.lastScorePercent}%`,
          })}
        </Text>
      </View>
      <Pill label={`${insight.masteryPercent}%`} tone={masteryTone} />
    </View>
  );
}

export function LessonMasteryRow({
  insight,
  title,
}: {
  insight: KangurMobileLessonsLessonMasteryItem;
  title: string;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const masteryTone = getLessonMasteryTone(insight.masteryPercent);
  const lastCompletedAt = insight.lastCompletedAt;
  const lastAttemptLabel =
    typeof lastCompletedAt === 'string' && lastCompletedAt !== ''
      ? new Intl.DateTimeFormat(getKangurMobileLocaleTag(locale), {
          dateStyle: 'medium',
          timeStyle: 'short',
        }).format(new Date(lastCompletedAt))
      : copy({
          de: 'kein Datum',
          en: 'no date',
          pl: 'brak daty',
        });

  return (
    <InsetPanel gap={10}>
      <LessonMasteryHeader insight={insight} title={title} masteryTone={masteryTone} />

      <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
        {copy({
          de: `Bestes Ergebnis ${insight.bestScorePercent}% • letzter Versuch ${lastAttemptLabel}`,
          en: `Best score ${insight.bestScorePercent}% • last attempt ${lastAttemptLabel}`,
          pl: `Najlepszy wynik ${insight.bestScorePercent}% • ostatnia próba ${lastAttemptLabel}`,
        })}
      </Text>

      <View style={{ flexDirection: 'column', gap: 8 }}>
        <LinkButton
          href={insight.lessonHref}
          label={copy({
            de: 'Lektion öffnen',
            en: 'Open lesson',
            pl: 'Otwórz lekcję',
          })}
          stretch
          tone='primary'
        />
        {renderLessonPracticeLink({
          href: insight.practiceHref,
          label: copy({
            de: 'Danach trainieren',
            en: 'Practice after',
            pl: 'Potem trenuj',
          }),
          fullWidth: true,
        })}
      </View>
    </InsetPanel>
  );
}

export function LessonBadgeChip({
  item,
}: {
  item: KangurMobileLessonsBadgeItem;
}): React.JSX.Element {
  return (
    <Pill
      label={`${item.emoji} ${item.name}`}
      tone={{
        backgroundColor: '#eef2ff',
        borderColor: '#c7d2fe',
        textColor: '#4338ca',
      }}
    />
  );
}

function LessonRecentResultHeader({
  item,
}: {
  item: KangurMobileLessonsRecentResultItem;
}): React.JSX.Element {
  const { locale } = useKangurMobileI18n();
  return (
    <View
      style={{
        flexDirection: 'row',
        justifyContent: 'space-between',
        alignItems: 'flex-start',
        gap: 12,
      }}
    >
      <View style={{ flex: 1, gap: 4 }}>
        <Text style={{ color: '#0f172a', fontSize: 15, fontWeight: '800' }}>
          {formatKangurMobileScoreOperation(item.result.operation, locale)}
        </Text>
        <Text style={{ color: '#64748b', fontSize: 12 }}>
          {formatKangurMobileScoreDateTime(item.result.created_date, locale)}
        </Text>
      </View>
      <Pill
        label={`${item.result.correct_answers}/${item.result.total_questions}`}
        tone={{
