export type KangurMobileActionButtonProps = {
  accessibilityHint?: string;
  accessibilityLabel?: string;
  borderRadius?: number;
  centered?: boolean;
  disabledOpacity?: number;
  disabled?: boolean;
  horizontalPadding?: number;
  label: string;
