  onPress: () => void | Promise<void>;
  stretch?: boolean;
  style?: StyleProp<ViewStyle>;
  textStyle?: StyleProp<TextStyle>;
  tone?: 'brand' | 'ghost' | 'primary' | 'secondary';
  verticalPadding?: number;
};

export type KangurMobileLinkButtonProps = {
